import pytest
import json
import os

from security.sanitizer import sanitize


class TestAllowedTags:
    """Test that safe tags are preserved."""

    def test_bold_tags(self):
        assert sanitize("<b>hello</b>") == "<b>hello</b>"

    def test_italic_tags(self):
        assert sanitize("<i>world</i>") == "<i>world</i>"

    def test_em_tags(self):
        assert sanitize("<em>emphasis</em>") == "<em>emphasis</em>"

    def test_strong_tags(self):
        assert sanitize("<strong>bold</strong>") == "<strong>bold</strong>"

    def test_anchor_with_href(self):
        result = sanitize('<a href="https://example.com">link</a>')
        assert 'href="https://example.com"' in result
        assert "<a" in result
        assert "link</a>" in result

    def test_lists(self):
        html = "<ul><li>item 1</li><li>item 2</li></ul>"
        result = sanitize(html)
        assert "<ul>" in result
        assert "<li>" in result

    def test_ordered_list(self):
        html = "<ol><li>first</li><li>second</li></ol>"
        result = sanitize(html)
        assert "<ol>" in result
        assert "<li>" in result

    def test_paragraph(self):
        assert sanitize("<p>text</p>") == "<p>text</p>"

    def test_br_tag(self):
        result = sanitize("line1<br>line2")
        assert "<br" in result
        assert "line1" in result
        assert "line2" in result


class TestScriptRemoval:
    """Test that script injection vectors are blocked."""

    def test_script_tag(self):
        result = sanitize("<script>alert('xss')</script>")
        assert "<script" not in result.lower()
        assert "alert" not in result

    def test_script_tag_uppercase(self):
        result = sanitize("<SCRIPT>alert('xss')</SCRIPT>")
        assert "<script" not in result.lower()

    def test_script_with_src(self):
        result = sanitize('<script src="evil.js"></script>')
        assert "<script" not in result.lower()


class TestEventHandlers:
    """Test that event handler attributes are stripped."""

    def test_onclick(self):
        result = sanitize('<div onclick="alert(1)">text</div>')
        assert "onclick" not in result.lower()

    def test_onerror(self):
        result = sanitize('<img onerror="alert(1)" src="x">')
        assert "onerror" not in result.lower()

    def test_onmouseover(self):
        result = sanitize('<span onmouseover="alert(1)">hover</span>')
        assert "onmouseover" not in result.lower()

    def test_onfocus(self):
        result = sanitize('<input onfocus="alert(1)">')
        assert "onfocus" not in result.lower()


class TestJavascriptURLs:
    """Test that javascript: protocol in URLs is blocked."""

    def test_javascript_href(self):
        result = sanitize('<a href="javascript:alert(1)">click</a>')
        assert "javascript:" not in result.lower()

    def test_javascript_href_encoded(self):
        result = sanitize('<a href="java&#115;cript:alert(1)">click</a>')
        assert "javascript" not in result.lower()
        assert "alert" not in result

    def test_javascript_href_whitespace(self):
        result = sanitize('<a href="  javascript:alert(1)">click</a>')
        assert "javascript:" not in result.lower()


class TestDangerousTags:
    """Test that dangerous tags are stripped."""

    def test_iframe(self):
        result = sanitize('<iframe src="evil.com"></iframe>')
        assert "<iframe" not in result.lower()

    def test_object(self):
        result = sanitize('<object data="evil.swf"></object>')
        assert "<object" not in result.lower()

    def test_embed(self):
        result = sanitize('<embed src="evil.swf">')
        assert "<embed" not in result.lower()

    def test_form(self):
        result = sanitize('<form action="evil.com"><input></form>')
        assert "<form" not in result.lower()


