# rendering/widgets.py
"""
Widget rendering module for Crowdpulse dashboards.

Handles rendering of individual dashboard widgets with user-customizable
content fields (titles, descriptions, custom HTML annotations).
"""

from typing import Optional
from security import sanitize


class Widget:
    """Represents a dashboard widget with customizable content."""

    def __init__(self, widget_id: str, widget_type: str):
        self.widget_id = widget_id
        self.widget_type = widget_type
        self._title: str = ""
        self._description: str = ""
        self._custom_content: str = ""

    @property
    def title(self) -> str:
        return self._title

    @title.setter
    def title(self, raw_title: str) -> None:
        self._title = sanitize(raw_title)

    @property
    def description(self) -> str:
        return self._description

    @description.setter
    def description(self, raw_description: str) -> None:
        self._description = sanitize(raw_description)

    @property
    def custom_content(self) -> str:
        return self._custom_content

    @custom_content.setter
    def custom_content(self, raw_content: str) -> None:
        self._custom_content = sanitize(raw_content)

    def render(self) -> dict:
        """Render the widget with all sanitized content."""
        return {
            'id': self.widget_id,
            'type': self.widget_type,
            'title': self._title,
            'description': self._description,
            'content': self._custom_content,
        }
